class ProductionSystem:
    def __init__(self):
        self.working_memory = set()  # Current facts
        self.rules = []  # List of (conditions, actions)

    def add_rule(self, conditions, actions):
        """Add a production rule: conditions is a set of facts,
           actions is a list of facts to add"""
        self.rules.append((conditions, actions))

    def forward_chain(self, goal=None):
        """Data-driven reasoning: infer new facts from known facts"""
        fired_rules = []

        while True:
            rule_fired = False

            for conditions, actions in self.rules:
                # Check if all conditions are satisfied
                if conditions.issubset(self.working_memory):
                    # Check if this rule hasn't already fired
                    if (conditions, actions) not in fired_rules:
                        # Execute actions (add new facts)
                        for action in actions:
                            if action not in self.working_memory:
                                self.working_memory.add(action)
                                print(f"Rule fired: {conditions} → {action}")

                        fired_rules.append((conditions, actions))
                        rule_fired = True

                        # Check if goal reached
                        if goal and goal in self.working_memory:
                            return True, self.working_memory

            if not rule_fired:
                break  # No more rules can fire

        return goal is None or goal in self.working_memory, self.working_memory

# Example usage
ps = ProductionSystem()
ps.working_memory = {'bird(penguin)', 'penguin(penguin)'}
ps.add_rule(
    {'bird(X)', 'NOT penguin(X)'},  
    {'flies(X)'}
)
ps.add_rule(
    {'penguin(X)'},
    {'NOT flies(X)'}
)

reached, facts = ps.forward_chain()
print(f"Final facts: {facts}")

import java.util.*;

public class BackwardChainer {
    private Map<String, List<Rule>> ruleMap = new HashMap<>();
    private Set<String> facts = new HashSet<>();

    static class Rule {
        String conclusion;
        Set<String> conditions;

        Rule(String conclusion, String... conditions) {
            this.conclusion = conclusion;
            this.conditions = new HashSet<>(Arrays.asList(conditions));
        }
    }

    public void addRule(Rule rule) {
        ruleMap.computeIfAbsent(rule.conclusion, k -> new ArrayList<>()).add(rule);
    }

    public void addFact(String fact) {
        facts.add(fact);
    }

    public boolean prove(String goal, Set<String> visited) {
        if (facts.contains(goal)) return true;
        if (visited.contains(goal)) return false;
        visited.add(goal);

        List<Rule> rules = ruleMap.get(goal);
        if (rules == null) return false;

        for (Rule rule : rules) {
            boolean allProven = true;
            for (String condition : rule.conditions) {
                if (!prove(condition, new HashSet<>(visited))) {
                    allProven = false;
                    break;
                }
            }
            if (allProven) {
                System.out.println("Proved: " + goal + " using rule: " + rule.conditions + " → " + goal);
                facts.add(goal);
                return true;
            }
        }
        return false;
    }

    public static void main(String[] args) {
        BackwardChainer bc = new BackwardChainer();
        bc.addFact("fever");
        bc.addFact("cough");
        bc.addRule(new Rule("cold", "fever", "cough"));
        bc.addRule(new Rule("flu", "fever", "body_ache"));

        boolean result = bc.prove("cold", new HashSet<>());
        System.out.println("Goal proved: " + result);
    }
}
